#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

inline int maximum(int a, int b, int c) {
    int k = (a <= b) ? b : a;
    return (k <= c) ? c : k;
}

__kernel void nw_kernel1(__global int* reference,
                         __global int* input_itemsets,
                         __global int* output_itemsets,
                         __local int* input_itemsets_l,
                         __local int* reference_l,
                         int max_cols,
                         int penalty,
                         int blk,
                         int block_width,
                         int worksize,
                         int offset_r,
                         int offset_c) {
    (void)output_itemsets;
    (void)block_width;
    (void)worksize;
    (void)offset_r;
    (void)offset_c;

    if (get_local_id(0) != 0) return;

    int b_index_x = (int)get_group_id(0);
    int b_index_y = blk - 1 - b_index_x;

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            reference_l[i * BLOCK_SIZE + j] =
                reference[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                          b_index_x * BLOCK_SIZE + j + 1];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) +
                               b_index_x * BLOCK_SIZE + j];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                maximum(input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] +
                            reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                        input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                        input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                           b_index_x * BLOCK_SIZE + j + 1] =
                input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

__kernel void nw_kernel2(__global int* reference,
                         __global int* input_itemsets,
                         __global int* output_itemsets,
                         __local int* input_itemsets_l,
                         __local int* reference_l,
                         int max_cols,
                         int penalty,
                         int blk,
                         int block_width,
                         int worksize,
                         int offset_r,
                         int offset_c) {
    (void)output_itemsets;
    (void)worksize;
    (void)offset_r;
    (void)offset_c;

    if (get_local_id(0) != 0) return;

    int gid = (int)get_group_id(0);
    int b_index_x = block_width - blk + gid;
    int b_index_y = block_width - 1 - gid;

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            reference_l[i * BLOCK_SIZE + j] =
                reference[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                          b_index_x * BLOCK_SIZE + j + 1];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) +
                               b_index_x * BLOCK_SIZE + j];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                maximum(input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] +
                            reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                        input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                        input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                           b_index_x * BLOCK_SIZE + j + 1] =
                input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}
